noncompliant:
// Mixing comment styles in the same file is inconsistent
/* This is a block comment at the top */

class MyClass {
public:
    // This is a single-line comment
    void method1();

    /* Another block comment */
    void method2();

    // Yet another single-line comment - Noncompliant: mixing styles
    void method3();
};

compliant:
// Consistent use of single-line comments throughout
// This file uses only single-line comment style

class MyClass {
public:
    // This method does something
    void method1();

    // This method does something else
    void method2();

    // This method does another thing
    void method3();
};

/* Consistent use of block comments throughout */
/* This file uses only block comment style */

class MyClass {
public:
    /* This method does something */
    void method1();

    /* This method does something else */
    void method2();

    /* This method does another thing */
    void method3();
};
